import { forwardRef, isValidElement } from "react";
import type { HTMLAttributes, ReactElement } from "react";
import { Slot } from "@radix-ui/react-slot";
import { clsx } from "clsx";
import * as styles from "./Text.css";
import type { TextVariant } from "./Text.config";
import { DEFAULT_TEXT_VARIANT } from "./Text.config";

export const textClassNames = styles.text.classNames.variants.variant;

export interface TextCustomProps {
  /**
   * The typography variant to apply
   * @default "body.base.normal"
   */
  variant?: TextVariant;

  /**
   * The content to render
   */
  children: ReactElement;
}

export interface TextProps
  extends
    Omit<HTMLAttributes<HTMLElement>, keyof TextCustomProps>,
    TextCustomProps {}

export const Text = forwardRef<HTMLElement, TextProps>(
  ({ variant = DEFAULT_TEXT_VARIANT, children, className, ...props }, ref) => {
    const textClassName = clsx(styles.text({ variant }), className);

    if (!isValidElement(children)) {
      return children;
    }

    return (
      <Slot ref={ref} className={textClassName} {...props}>
        {children}
      </Slot>
    );
  }
);

Text.displayName = "Text";
